arguments.command:
# Check if the bat file's cmd process is still running and what it's doing
$cmd = Get-Process -Id 8828 -ErrorAction SilentlyContinue
if ($cmd) {
    Write-Output "CMD process 8828 still running"
    # Check its child processes
    $children = Get-CimInstance -ClassName Win32_Process -Filter "ParentProcessId=8828"
    Write-Output "Child processes:"
    $children | Format-Table ProcessId, Name, CommandLine -AutoSize -Wrap
} else {
    Write-Output "CMD process 8828 has exited"
}

# Also check log file
$log = Get-Item "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log" -ErrorAction SilentlyContinue
if ($log) {
    Write-Output "Log file: $($log.Length) bytes, LastWrite: $($log.LastWriteTime)"
} else {
    Write-Output "No log file found"
}
